public class BaiTap1 {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		// 1. Khai báo các biến
        int a = 15;
        int b = 4;
        double c = 3.5;

        // 2. Tính toán
        int tong = a + b;
        double thuong = a / c;
        int phanDu = a % b;

        // 3. In kết quả
        System.out.println("Tổng: " + tong);
        System.out.println("Thương: " + thuong);
        System.out.println("Phần dư: " + phanDu);

	}

}
